mapper.select:
SELECT

FROM crm_shipping s
WHERE s.deleted = 0

    AND s.shipping_no LIKE CONCAT('%', #{query.shippingNo}, '%')


    AND s.order_id = #{query.orderId}


    AND s.order_no LIKE CONCAT('%', #{query.orderNo}, '%')


    AND s.customer_id = #{query.customerId}


    AND s.customer_name LIKE CONCAT('%', #{query.customerName}, '%')


    AND s.carrier = #{query.carrier}


    AND s.tracking_no LIKE CONCAT('%', #{query.trackingNo}, '%')


    AND s.status = #{query.status}


    AND s.customs_status = #{query.customsStatus}


    AND s.shipping_date >= #{query.startDate}


    AND s.shipping_date <= #{query.endDate}


    AND s.owner_id = #{query.ownerId}


    AND s.department_id = #{query.departmentId}

ORDER BY s.created_time DESC
